import { Link } from 'react-router-dom';

const users = [
  { id: 101, name: "Rahul" },
  { id: 102, name: "Priya" },
  { id: 103, name: "Arjun" },
];

function UsersList() {
  return (
    <div>
      <h2>Users</h2>
      {users.map(user => (
        <div key={user.id}>
          <Link to={`/users/${user.id}`}>{user.name}</Link>
        </div>
      ))}
    </div>
  );
}

export default UsersList;